/**
 * ExperienceSelector Component
 * Handles experience level dropdown selection
 */

import { BulletUtils } from '../utils';
import { ExperienceLevel, EXPERIENCE_LEVELS } from '../types';

export interface ExperienceSelectorConfig {
  onLevelChange: (level: ExperienceLevel) => void;
}

export class ExperienceSelector {
  private config: ExperienceSelectorConfig;
  private container: HTMLElement | null = null;
  private selectElement: HTMLElement | null = null;
  private dropdown: HTMLElement | null = null;
  private isDropdownOpen: boolean = false;
  private selectedLevel: ExperienceLevel | null = null;

  constructor(config: ExperienceSelectorConfig) {
    this.config = config;
  }

  render(): HTMLElement {
    const group = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'input-group',
    );

    const label = BulletUtils.createElement<HTMLLabelElement>(
      'label',
      'input-label',
    );
    label.textContent = 'EXPERIENCE LEVEL';
    group.appendChild(label);

    const selectWrapper = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'select-wrapper',
    );

    // Custom select display
    this.selectElement = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'select',
    );
    const display = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'select-display placeholder',
    );
    display.innerHTML = `<span>Select experience level</span><span class="select-arrow"><i class="fa-solid fa-chevron-down"></i></span>`;
    this.selectElement.appendChild(display);

    // Dropdown
    this.dropdown = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'select-dropdown',
    );
    this.dropdown.style.display = 'none';

    EXPERIENCE_LEVELS.forEach((level) => {
      const option = BulletUtils.createElement<HTMLDivElement>(
        'div',
        'dropdown-item',
      );
      option.textContent = level.label;
      option.dataset['value'] = level.value;

      option.addEventListener('click', () => {
        this.selectLevel(level.value, level.label);
      });

      this.dropdown?.appendChild(option);
    });

    selectWrapper.appendChild(this.selectElement);
    selectWrapper.appendChild(this.dropdown);
    group.appendChild(selectWrapper);

    this.container = group;
    this.setupEventListeners();
    return group;
  }

  private setupEventListeners(): void {
    if (!this.selectElement) return;

    this.selectElement.addEventListener('click', (e) => {
      e.stopPropagation();
      this.toggleDropdown();
    });

    // Close dropdown on outside click
    document.addEventListener('click', () => {
      this.closeDropdown();
    });
  }

  private toggleDropdown(): void {
    if (this.isDropdownOpen) {
      this.closeDropdown();
    } else {
      this.openDropdown();
    }
  }

  private openDropdown(): void {
    if (this.dropdown) {
      this.dropdown.style.display = 'block';
      this.isDropdownOpen = true;
    }
  }

  private closeDropdown(): void {
    if (this.dropdown) {
      this.dropdown.style.display = 'none';
      this.isDropdownOpen = false;
    }
  }

  private selectLevel(value: ExperienceLevel, label: string): void {
    this.selectedLevel = value;

    // Update display
    if (this.selectElement) {
      const display = this.selectElement.querySelector('.select-display');
      if (display) {
        display.classList.remove('placeholder');
        display.innerHTML = `<span>${label}</span><span class="select-arrow"><i class="fa-solid fa-chevron-down"></i></span>`;
      }
    }

    this.closeDropdown();
    this.config.onLevelChange(value);
  }

  getValue(): ExperienceLevel | null {
    return this.selectedLevel;
  }

  setValue(value: ExperienceLevel): void {
    const level = EXPERIENCE_LEVELS.find((l) => l.value === value);
    if (level) {
      this.selectLevel(level.value, level.label);
    }
  }

  reset(): void {
    this.selectedLevel = null;
    if (this.selectElement) {
      const display = this.selectElement.querySelector('.select-display');
      if (display) {
        display.classList.add('placeholder');
        display.innerHTML = `<span>Select experience level</span><span class="select-arrow"><i class="fa-solid fa-chevron-down"></i></span>`;
      }
    }
  }

  getIsDropdownOpen(): boolean {
    return this.isDropdownOpen;
  }
}
