// Rezi Bullet Point Generator SDK
import './styles.css';

export * from './components';
export * from './types';
export * from './utils';

// Load FontAwesome Pro Kit (same kit as app-react)
function loadFontAwesomeKit() {
  if (typeof document === 'undefined') return;
  const FA_KIT_ID = 'f5adea20e2';
  // Skip if already loaded
  if (document.querySelector(`script[src*="kit.fontawesome.com/${FA_KIT_ID}"]`))
    return;
  const script = document.createElement('script');
  script.src = `https://kit.fontawesome.com/${FA_KIT_ID}.js`;
  script.crossOrigin = 'anonymous';
  script.async = true;
  document.head.appendChild(script);
}

// Auto-initialize SDK when loaded in browser
if (typeof window !== 'undefined') {
  loadFontAwesomeKit();
  // Make SDK available globally
  import('./components').then((components) => {
    import('./utils').then((utils) => {
      (window as any).ReziBulletSDK = {
        ...components,
        ...utils,
      };

      // Auto-initialize if data-bullet-generator exists
      const autoInit = () => {
        const container = document.querySelector('[data-bullet-generator]');
        if (container && !container.hasAttribute('data-rezi-initialized')) {
          const isDev = container.hasAttribute('data-dev');
          const ctaUrl = container.getAttribute('data-cta-url');
          const maxSkills = container.getAttribute('data-max-skills');
          const recaptchaKey = container.getAttribute('data-recaptcha-key');

          new components.BulletPointGenerator({
            containerSelector: '[data-bullet-generator]',
            isDev: isDev || false,
            ctaUrl: ctaUrl || undefined,
            maxSkillSelection: maxSkills ? parseInt(maxSkills, 10) : undefined,
            recaptchaSiteKey: recaptchaKey || undefined,
          });

          container.setAttribute('data-rezi-initialized', 'true');
        }
      };

      // Try to initialize immediately or wait for DOM
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', autoInit);
      } else {
        autoInit();
      }
    });
  });
}
