/**
 * Get fallback skills based on job title category
 */
export function getFallbackSkillsForJob(jobTitle: string): string[] {
  const category = detectJobCategory(jobTitle);
  return CATEGORY_FALLBACK_SKILLS[category] ?? GENERIC_FALLBACK_SKILLS;
}

/**
 * Detect job category from job title keywords
 */
export function detectJobCategory(jobTitle: string): string {
  const normalized = jobTitle.toLowerCase();

  if (
    normalized.includes('developer') ||
    normalized.includes('engineer') ||
    normalized.includes('programmer') ||
    normalized.includes('software')
  ) {
    return 'developer';
  }

  if (
    normalized.includes('manager') ||
    normalized.includes('director') ||
    normalized.includes('lead')
  ) {
    return 'manager';
  }

  if (
    normalized.includes('designer') ||
    normalized.includes('ux') ||
    normalized.includes('ui')
  ) {
    return 'designer';
  }

  if (normalized.includes('analyst') || normalized.includes('data scientist')) {
    return 'analyst';
  }

  if (normalized.includes('marketing') || normalized.includes('seo')) {
    return 'marketing';
  }

  if (
    normalized.includes('sales') ||
    normalized.includes('account executive')
  ) {
    return 'sales';
  }

  return 'generic';
}
