/**
 * JobTitleInput Component
 * Handles job title input field with autocomplete functionality
 */

import { BulletUtils } from '../utils';

export interface JobTitleInputConfig {
  placeholder?: string;
  onTitleChange: (title: string) => void;
  onTitleSelect?: (title: string) => void;
}

export class JobTitleInput {
  private config: JobTitleInputConfig;
  private container: HTMLElement | null = null;
  private inputElement: HTMLInputElement | null = null;
  private autocompleteList: HTMLElement | null = null;
  private isAutocompleteOpen: boolean = false;

  constructor(config: JobTitleInputConfig) {
    this.config = config;
  }

  render(): HTMLElement {
    const group = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'input-group',
    );

    const label = BulletUtils.createElement<HTMLLabelElement>(
      'label',
      'input-label',
    );
    label.textContent = 'JOB TITLE';
    group.appendChild(label);

    const inputWrapper = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'input-wrapper',
    );

    this.inputElement = BulletUtils.createElement<HTMLInputElement>(
      'input',
      'input',
    );
    this.inputElement.type = 'text';
    this.inputElement.placeholder =
      this.config.placeholder || 'e.g., Product Manager';
    inputWrapper.appendChild(this.inputElement);

    // Autocomplete list
    this.autocompleteList = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'autocomplete',
    );
    this.autocompleteList.style.display = 'none';
    inputWrapper.appendChild(this.autocompleteList);

    group.appendChild(inputWrapper);
    this.container = group;

    this.setupEventListeners();
    return group;
  }

  private setupEventListeners(): void {
    if (!this.inputElement) return;

    this.inputElement.addEventListener('input', (e) => {
      const value = (e.target as HTMLInputElement).value;
      this.config.onTitleChange(value);
    });

    // Close autocomplete on outside click
    document.addEventListener('click', (e) => {
      if (this.container && !this.container.contains(e.target as Node)) {
        this.closeAutocomplete();
      }
    });
  }

  showAutocomplete(suggestions: string[]): void {
    if (!this.autocompleteList) return;

    if (suggestions.length === 0) {
      this.closeAutocomplete();
      return;
    }

    this.autocompleteList.innerHTML = '';

    suggestions.forEach((suggestion) => {
      const item = BulletUtils.createElement<HTMLDivElement>(
        'div',
        'autocomplete-item',
      );
      item.textContent = suggestion;

      item.addEventListener('click', () => {
        if (this.inputElement) {
          this.inputElement.value = suggestion;
          this.config.onTitleChange(suggestion);
          if (this.config.onTitleSelect) {
            this.config.onTitleSelect(suggestion);
          }
        }
        this.closeAutocomplete();
      });

      this.autocompleteList?.appendChild(item);
    });

    this.autocompleteList.style.display = 'block';
    this.isAutocompleteOpen = true;
  }

  closeAutocomplete(): void {
    if (this.autocompleteList) {
      this.autocompleteList.style.display = 'none';
      this.isAutocompleteOpen = false;
    }
  }

  getValue(): string {
    return this.inputElement?.value || '';
  }

  setValue(value: string): void {
    if (this.inputElement) {
      this.inputElement.value = value;
    }
  }

  focus(): void {
    this.inputElement?.focus();
  }

  getIsAutocompleteOpen(): boolean {
    return this.isAutocompleteOpen;
  }
}
