/**
 * API Configuration for Bulletpoint SDK
 * Centralizes all API settings, URLs, and fallback data
 */

export interface ApiConfig {
  baseUrl: string;
  skillExploreEndpoint: string;
  bulletGenerateEndpoint: string;
  timeout: number;
  maxRetries: number;
  rateLimitPerDay: number;
  bulletRateLimitPerDay: number;
}

/** reCAPTCHA Enterprise site keys (public) — 빌드 환경변수로 주입, 없으면 기본값 사용 */
export const RECAPTCHA_SITE_KEY_DEV =
  process.env['RECAPTCHA_SITE_KEY_DEV'] ??
  '6LchNU0qAAAAABJWpEGPPrRjiMM7rj3JYTylBDn1';
export const RECAPTCHA_SITE_KEY_PROD =
  process.env['RECAPTCHA_SITE_KEY_PROD'] ??
  '6LeGtEgqAAAAAAi89fMo241vMKH3C9QRLH0a9nzC';

export const getRecaptchaSiteKey = (isDev: boolean): string =>
  isDev ? RECAPTCHA_SITE_KEY_DEV : RECAPTCHA_SITE_KEY_PROD;

/**
 * Get API configuration based on environment
 */
export const getApiConfig = (isDev: boolean): ApiConfig => ({
  baseUrl: isDev ? 'https://dev-api.rezi.ai' : 'https://api.rezi.ai',
  skillExploreEndpoint: '/v1/public/skill-explore',
  bulletGenerateEndpoint: '/v1/ai/ac_public',
  timeout: 30000,
  maxRetries: 0,
  rateLimitPerDay: 999999, // No client-side limit for skill-explore (gateway: 10/min)
  bulletRateLimitPerDay: 3,
});

